import{_ as a,o as n,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Introducing Branch Activation","description":"","frontmatter":{"title":"Introducing Branch Activation","slug":"introducing-branch-activation"},"headers":[],"relativePath":"account-hub/introducing-branch-activation.md","filePath":"account-hub/introducing-branch-activation.md"}'),r={name:"account-hub/introducing-branch-activation.md"};function o(s,e,c,l,d,h){return n(),t("div",null,[...e[0]||(e[0]=[i('<p><em>[Image: Mobile and desktop interface showcasing social media engagement and advertising features.]</em>.png)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With Branch Activation, you can unify all your enterprise linking needs in one secure, scalable solution with app Short Links, web Short Links, and QR codes.</p><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><ul><li>Improve clickthrough rates and engagement with short, branded, trackable links in social posts and profiles.</li><li>Create and manage web and app links and QR codes in one platform to reduce redundancy and unify analytics across use cases.</li><li>Improve efficiency and gain control with centralized link governance, domain management, and role-based permissions.</li><li>Instill trust and boost clickthrough rates with recognizable branded links and QR codes.</li></ul><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><ul><li><strong>Social</strong>: Improve clickthrough rates and engagement with short, branded, trackable links in social posts and profiles.</li><li><strong>QR:</strong> Customize QR code logos, colors, and shapes to drive and track digital actions from offline with up to 80% better performance.</li><li><strong>SMS</strong>: Short, smart links save cost and improve clickthrough rates while reliably taking users to the right content on web or app.</li><li><strong>Sharing</strong>: Enable easy content distribution from your share sheets, and learn where and how your content is spreading.</li></ul><h2 id="additional-resources" tabindex="-1">Additional resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional resources&quot;">​</a></h2><p>Check out our <a href="./packaging.html">Packaging</a> and <a href="./products.html">Products</a> pages to learn more about Activation. If you’re ready to get started, <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">reach out to our sales team</a>.</p><p>If you’re looking for resources about using Activation, check out the following article categories:</p><ul><li><a href="./create-branch-links-index.html">Create Links</a></li><li><a href="./manage-links-index.html">Manage Links</a></li><li><a href="./verify-links-index.html">Verify Links</a></li></ul>',11)])])}const p=a(r,[["render",o]]);export{g as __pageData,p as default};
